import { Component, inject } from '@angular/core';
import { FormBuilder, Validators, ReactiveFormsModule } from '@angular/forms';
import { HttpClient, HttpClientModule } from '@angular/common/http';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [ReactiveFormsModule, HttpClientModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export default class AppComponent {
  // Function-based DI to match the SDK environment
  private fb = inject(FormBuilder);
  private http = inject(HttpClient);

  // Reactive contact form with basic validation
  contactForm = this.fb.group({
    name: ['', [Validators.required]],
    email: ['', [Validators.required, Validators.email]],
    message: ['', [Validators.required, Validators.minLength(10)]],
  });

  isSubmitting = false;
  successMessage = '';
  errorMessage = '';

  get f() {
    return this.contactForm.controls;
  }

  submit(): void {
    // Clear previous messages
    this.successMessage = '';
    this.errorMessage = '';

    // Show validation errors if form is invalid
    this.contactForm.markAllAsTouched();
    if (this.contactForm.invalid) {
      return;
    }

    this.isSubmitting = true;

    // Fake JSON API endpoint for this exercise
    this.http.post('https://jsonplaceholder.typicode.com/posts', this.contactForm.value).subscribe({
      next: () => {
        this.isSubmitting = false;
        this.successMessage = 'Your message has been sent. Thank you!';
        this.contactForm.reset();
      },
      error: () => {
        this.isSubmitting = false;
        this.errorMessage = 'Something went wrong. Please try again.';
      },
    });
  }
}

// Also export a named AppComponent so the bootstrap import always works
export { AppComponent };
